void add(String newcode) {
  maybeEndStatement();

  if (newcode.length() == 0) {
    return;
  }

  char c = newcode.charAt(0);
  if ((isWordChar(c) || c == '\\') &&
      isWordChar(getLastChar())) {
    // need space to separate. This is not pretty printing.
    // For example: "return foo;"
    append(" ");
  }

  // Do not allow a forward slash to appear after a DIV or another slash,
  // to avoid accidentally creating a comment or a regexp ambiguity.
  if (c == '/' && getLastChar() == '/') {
    append(" ");
  }

  append(newcode);
}
